declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/portal_estudiante_aula.php';$pdo=obtenerConexion();$tag='c7e8_'.bin2hex(random_bytes(4));$ids=[];$ok=[];$assert=static function(bool$c,string$m)use(&$ok){if(!$c)throw new RuntimeException('FALLO: '.$m);$ok[]=$m;};
try{$activo='$activo';$clave='$clave';
 $q=$pdo->prepare("INSERT INTO usuarios(nombre,apellido,nombre_usuario,correo,password,rol,estado,email_verificado,perfil_estado,terminos_aceptados_at) VALUES('Estudiante','Aula',:n,:c,:p,'usuario','activo',1,'completo',NOW())");$q->execute(['n'=>$tag,'c'=>$tag.'@example.invalid','p'=>password_hash('Temporal123!',PASSWORD_DEFAULT)]);$u=(int)$pdo->lastInsertId();$ids['usuarios'][]=$u;
 $q=$pdo->prepare("INSERT INTO usuarios(nombre,apellido,nombre_usuario,correo,password,rol,estado,email_verificado,perfil_estado,terminos_aceptados_at) VALUES('Docente','Aula',:n,:c,:p,'docente','activo',1,'completo',NOW())");$q->execute(['n'=>'doc_'.$tag,'c'=>'doc_'.$tag.'@example.invalid','p'=>password_hash('Temporal123!',PASSWORD_DEFAULT)]);$d=(int)$pdo->lastInsertId();$ids['usuarios'][]=$d;
